const task = $('Start').item.json;
const phases = [
  { id: 'phase_0a', name: 'Theme Preview',        game_refs: [] },
  { id: 'phase_0b', name: 'Flash Cards',           game_refs: [] },
  { id: 'phase_1',  name: 'Memory Sprint',         game_refs: [] },
  { id: 'phase_2',  name: 'Story Mode',            game_refs: [] },
  { id: 'phase_3',  name: 'Game Breaks',           game_refs: ['tile_match','codebreaker','tic_tac_toe'] },
  { id: 'phase_4',  name: 'Real-Life Challenge',   game_refs: [] },
  { id: 'phase_5',  name: 'Consolidation',         game_refs: [] },
  { id: 'phase_6',  name: 'Final Boss',            game_refs: [] },
  { id: 'phase_7',  name: 'Reflection',            game_refs: [] }
];
return phases.map(p => ({ json: { ...task, phase_id: p.id, phase_name: p.name, game_refs: p.game_refs } }));

const item = $json;
const fs = require('fs');

const basePrompt = fs.readFileSync('/home/node/nets/frameworks/system/phase_worker_base.md', 'utf8');
const unifiedSchema = fs.readFileSync('/home/node/nets/frameworks/unified/schema.md', 'utf8');
const subjectFramework = fs.readFileSync('/home/node/nets/frameworks/subjects/matematika.md', 'utf8');
const phaseSpec = fs.readFileSync(`/home/node/nets/frameworks/unified/${item.phase_id}.md`, 'utf8');
const lessonJson = fs.readFileSync(`/home/node/nets/nets-output/${item.lesson_id}_lesson.json`, 'utf8');
const outputSchema = fs.readFileSync(`/home/node/nets/frameworks/schemas/${item.phase_id}.json`, 'utf8');

let gameContent = '';
if (item.game_refs && item.game_refs.length > 0) {
  item.game_refs.forEach(g => {
    try { gameContent += fs.readFileSync(`/home/node/nets/frameworks/games/${g}.md`, 'utf8') + '\n\n'; } catch(e) {}
  });
}

const systemMessage = [
  '## LAYER 1: SYSTEM INVARIANTS\n' + basePrompt,
  '## LAYER 2: UNIFIED FRAMEWORK SCHEMA\n' + unifiedSchema,
  '## LAYER 3: SUBJECT FRAMEWORK\n' + subjectFramework,
  '## LAYER 4: PHASE SPECIFICATION\n' + phaseSpec,
  gameContent ? ('## LAYER 5: GAME MECHANICS\n' + gameContent) : ''
].filter(Boolean).join('\n\n---\n\n');

const userMessage = [
  `## LAYER 6: LESSON CONTENT\n${lessonJson}`,
  `## LAYER 7: TASK CONTEXT\n{"grade": ${item.grade}, "lang": "${item.lang}", "subject": "${item.subject}", "lesson_id": "${item.lesson_id}", "phase_id": "${item.phase_id}"}`,
  `## LAYER 8: TASK\nProduce the ${item.phase_name} phase deliverable. Return ONLY valid JSON matching this schema exactly:\n${outputSchema}`
].join('\n\n---\n\n');

const payload = {
  model: 'kimi-k2-0711-preview',
  messages: [
    { role: 'system', content: systemMessage },
    { role: 'user', content: userMessage }
  ],
  response_format: { type: 'json_object' },
  temperature: 0.3,
  max_tokens: 8000
};

return [{ json: { payload, ...item, prompt_hash: Buffer.from(systemMessage).toString('base64').substring(0,32), call_start: Date.now() } }];

const response = $json;
const meta = $('Compose Phase Prompt').item.json;

let phaseJson;
try {
  phaseJson = JSON.parse(response.choices[0].message.content);
} catch(e) {
  throw new Error(`Phase ${meta.phase_id} invalid JSON: ` + e.message);
}

const tokensIn = response.usage?.prompt_tokens || 0;
const tokensOut = response.usage?.completion_tokens || 0;
const costUsd = (tokensIn * 0.60 + tokensOut * 2.50) / 1000000;
const cacheHit = response.usage?.prompt_cache_hit_tokens ? (response.usage.prompt_cache_hit_tokens / tokensIn * 100) : 0;
const latency = Date.now() - meta.call_start;

return [{ json: {
  phase_output: phaseJson,
  task_id: meta.task_id,
  lesson_id: meta.lesson_id,
  phase_id: meta.phase_id,
  tokens_in: tokensIn,
  tokens_out: tokensOut,
  cost_usd: costUsd,
  cache_hit_pct: cacheHit,
  latency_ms: latency,
  prompt_hash: meta.prompt_hash
}}];
